// ADAServer is the server API for ADA service.
type ADAServer interface {
	// User 账户管理
	Login(context.Context, *LoginReq) (*LoginReply, error)
	Logout(context.Context, *LogoutReq) (*LogoutReply, error)
	ListUser(context.Context, *ListUserReq) (*ListUserReply, error)
	AddUser(context.Context, *AddUserReq) (*AddUserReply, error)
	UpdateUser(context.Context, *UpdateUserReq) (*UpdateUserReply, error)
	UpdateUserPassword(context.Context, *UpdateUserPasswordReq) (*UpdateUserPasswordReply, error)
	DeleteUser(context.Context, *DeleteUserReq) (*DeleteUserReply, error)
	UserExists(context.Context, *UserExistsReq) (*UserExistsReply, error)
	// Authority 二次验证相关接口
	CheckMfa(context.Context, *CheckMfaReq) (*CheckMfaReply, error)
	EnableMfa(context.Context, *EnableMfaReq) (*EnableMfaReply, error)
	DisableMfa(context.Context, *DisableMfaReq) (*DisableMfaReply, error)
	UpdateAvatar(context.Context, *UpdateAvatarReq) (*UpdateAvatarReply, error)
	ResetPassword(context.Context, *ResetPasswordReq) (*ResetPasswordReply, error)
	GetPwdUpdateTm(context.Context, *GetPwdUpdateTmReq) (*GetPwdUpdateTmReply, error)
	// Domain
	ListDomain(context.Context, *ListDomainReq) (*ListDomainReply, error)
	AddDomain(context.Context, *AddDomainReq) (*AddDomainReply, error)
	TestDomain(context.Context, *TestDomainReq) (*TestDomainReply, error)
	UpdateDomain(context.Context, *UpdateDomainReq) (*UpdateDomainReply, error)
	DeleteDomain(context.Context, *DeleteDomainReq) (*DeleteDomainReply, error)
	UpdateDomainData(context.Context, *UpdateDomainDataReq) (*UpdateDomainDataReply, error)
	// sensor
	ListSensor(context.Context, *ListSensorReq) (*ListSensorReply, error)
	UpdateSensor(context.Context, *UpdateSensorReq) (*UpdateSensorReply, error)
	DownloadSensor(context.Context, *DownloadSensorReq) (*DownloadSensorReply, error)
	CmdSensor(context.Context, *CmdSensorReq) (*CmdSensorReply, error)
	UpdateSensorVersion(context.Context, *UpdateSensorVersionReq) (*UpdateSensorVersionReply, error)
	// 系统信息
	// 1.基本信息
	GetSystemInfo(context.Context, *GetSystemInfoReq) (*GetSystemInfoReply, error)
	GetCompanyIcon(context.Context, *GetCompanyIconReq) (*GetCompanyIconReply, error)
	UpdateCompanyIcon(context.Context, *UpdateCompanyIconReq) (*UpdateCompanyIconReply, error)
	UpdateNtpAddress(context.Context, *UpdateNtpAddressReq) (*UpdateNtpAddressReply, error)
	UpdateSystemLanguage(context.Context, *UpdateSystemLanguageReq) (*UpdateSystemLanguageReply, error)
	// 2.系统监控: load|cpu|mem|net_rx|net_tx
	GetSystemStats(context.Context, *GetSystemStatsReq) (*GetSystemStatsReply, error)
	SetSystemStatsCfg(context.Context, *SetSystemStatsCfgReq) (*SetSystemStatsCfgReply, error)
	// 3.授权管理
	GetLicense(context.Context, *GetLicenseReq) (*GetLicenseReply, error)
	UpdateLicense(context.Context, *UpdateLicenseReq) (*UpdateLicenseReply, error)
	// 4.调试工具
	NetworkDebug(context.Context, *NetworkDebugReq) (*NetworkDebugReply, error)
	// 告警配置
	ListNotifyConf(context.Context, *ListNotifyConfReq) (*ListNotifyConfReply, error)
	UpdateNotifyConf(context.Context, *UpdateNotifyConfReq) (*UpdateNotifyConfReply, error)
	EnableNotifyConf(context.Context, *EnableNotifyConfReq) (*EnableNotifyConfReply, error)
	TestNotifyConf(context.Context, *TestNotifyConfReq) (*TestNotifyConfReply, error)
	// 导出管理
	ListExportTask(context.Context, *ListExportTaskReq) (*ListExportTaskReply, error)
	AddExportTask(context.Context, *AddExportTaskReq) (*AddExportTaskReply, error)
	DeleteExportTask(context.Context, *DeleteExportTaskReq) (*DeleteExportTaskReply, error)
	// 消息中心
	ListNotify(context.Context, *ListNotifyReq) (*ListNotifyReply, error)
	UpdateNotify(context.Context, *UpdateNotifyReq) (*UpdateNotifyReply, error)
	StatsNotify(context.Context, *StatsNotifyReq) (*StatsNotifyReply, error)
	// 日志审计
	ListAuditLog(context.Context, *ListAuditLogReq) (*ListAuditLogReply, error)
	// //////////////////////////////
	// threat威胁检测dashboard
	ThreatTops(context.Context, *ThreatTopsReq) (*ThreatTopsReply, error)
	ThreatTrends(context.Context, *ThreatTrendsReq) (*ThreatTrendsReply, error)
	// threat威胁检测
	ListThreat(context.Context, *ListThreatReq) (*ListThreatReply, error)
	GetThreatNames(context.Context, *GetThreatNamesReq) (*GetThreatNamesReply, error)
	ListThreatRule(context.Context, *ListThreatRuleReq) (*ListThreatRuleReply, error)
	ActionThreatRule(context.Context, *ActionThreatRuleReq) (*ActionThreatRuleReply, error)
	GetThreat(context.Context, *GetThreatReq) (*GetThreatReply, error)
	ActionThreat(context.Context, *ActionThreatReq) (*ActionThreatReply, error)
	ListActivity(context.Context, *ListActivityReq) (*ListActivityReply, error)
	GetActivityNames(context.Context, *GetActivityNamesReq) (*GetActivityNamesReply, error)
	GetActivity(context.Context, *GetActivityReq) (*GetActivityReply, error)
	ListThreatConf(context.Context, *ListThreatConfReq) (*ListThreatConfReply, error)
	UpdateThreatConf(context.Context, *UpdateThreatConfReq) (*UpdateThreatConfReply, error)
	ListSensitiveEntry(context.Context, *ListSensitiveEntryReq) (*ListSensitiveEntryReply, error)
	AddSensitiveEntry(context.Context, *AddSensitiveEntryReq) (*AddSensitiveEntryReply, error)
	ListDomainEntry(context.Context, *ListDomainEntryReq) (*ListDomainEntryReply, error)
	DeleteSensitiveEntry(context.Context, *DeleteSensitiveEntryReq) (*DeleteSensitiveEntryReply, error)
	ListThreatWhitelist(context.Context, *ListThreatWhitelistReq) (*ListThreatWhitelistReply, error)
	GetThreatWhitelistField(context.Context, *GetThreatWhitelistFieldReq) (*GetThreatWhitelistFieldReply, error)
	AddThreatWhitelist(context.Context, *AddThreatWhitelistReq) (*AddThreatWhitelistReply, error)
	UpdateThreatWhitelist(context.Context, *UpdateThreatWhitelistReq) (*UpdateThreatWhitelistReply, error)
	DeleteThreatWhitelist(context.Context, *DeleteThreatWhitelistReq) (*DeleteThreatWhitelistReply, error)
	ListThreatBlock(context.Context, *ListThreatBlockReq) (*ListThreatBlockReply, error)
	AddThreatBlock(context.Context, *AddThreatBlockReq) (*AddThreatBlockReply, error)
	UpdateThreatBlock(context.Context, *UpdateThreatBlockReq) (*UpdateThreatBlockReply, error)
	DeleteThreatBlock(context.Context, *DeleteThreatBlockReq) (*DeleteThreatBlockReply, error)
	// //////////////////////////////
	// scanrisk主动检测dashboard
	ScanRiskStats(context.Context, *ScanRiskStatsReq) (*ScanRiskStatsReply, error)
	// scanrisk主动检测
	ListBaseline(context.Context, *ListBaselineReq) (*ListBaselineReply, error)
	GetBaseline(context.Context, *GetBaselineReq) (*GetBaselineReply, error)
	ListLeak(context.Context, *ListLeakReq) (*ListLeakReply, error)
	ListWeakPwd(context.Context, *ListWeakPwdReq) (*ListWeakPwdReply, error)
	// 任务管理
	ListScanTask(context.Context, *ListScanTaskReq) (*ListScanTaskReply, error)
	GetScanTask(context.Context, *GetScanTaskReq) (*GetScanTaskReply, error)
	AddScanTask(context.Context, *AddScanTaskReq) (*AddScanTaskReply, error)
	RecheckScanTask(context.Context, *RecheckScanTaskReq) (*RecheckScanTaskReply, error)
	DeleteScanTask(context.Context, *DeleteScanTaskReq) (*DeleteScanTaskReply, error)
	// 扫描配置
	ListScanConf(context.Context, *ListScanConfReq) (*ListScanConfReply, error)
	SetScanConf(context.Context, *SetScanConfReq) (*SetScanConfReply, error)
	GetScanConf(context.Context, *GetScanConfReq) (*GetScanConfReply, error)
	GetScanTmplNames(context.Context, *GetScanTmplNamesReq) (*GetScanTmplNamesReply, error)
	UpdateScanConf(context.Context, *UpdateScanConfReq) (*UpdateScanConfReply, error)
	// 扫描模板
	ListScanTmpl(context.Context, *ListScanTmplReq) (*ListScanTmplReply, error)
	GetScanTmpl(context.Context, *GetScanTmplReq) (*GetScanTmplReply, error)
	UpdateScanTmpl(context.Context, *UpdateScanTmplReq) (*UpdateScanTmplReply, error)
	DeleteScanTmpl(context.Context, *DeleteScanTmplReq) (*DeleteScanTmplReply, error)
	AddScanTmpl(context.Context, *AddScanTmplReq) (*AddScanTmplReply, error)
	ListScanPlugin(context.Context, *ListScanPluginReq) (*ListScanPluginReply, error)
	// 安全大盘
	DashboardStats(context.Context, *DashboardStatsReq) (*DashboardStatsReply, error)
	DashboardTrends(context.Context, *DashboardTrendsReq) (*DashboardTrendsReply, error)
	DashboardLogStats(context.Context, *DashboardLogStatsReq) (*DashboardLogStatsReply, error)
}

